import{c as r,Q as a,j as e,m as l}from"./chunks/framework.DpF7k2f3.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"zh/appendix/appendix-c.md","filePath":"zh/appendix/appendix-c.md"}'),i={name:"zh/appendix/appendix-c.md"};function d(n,t,h,o,s,g){return a(),e("div",null,[...t[0]||(t[0]=[l('<h5 id="附录c-推荐学习资源完整清单" tabindex="-1">附录C 推荐学习资源完整清单 <a class="header-anchor" href="#附录c-推荐学习资源完整清单" aria-label="Permalink to &quot;附录C 推荐学习资源完整清单&quot;">​</a></h5><blockquote><p>学习AI应用开发，就像攀登一座高山。本附录精心整理了从入门到进阶的各类优质资源，包括必读书籍、精品课程、开源项目、社区论坛和官方文档。这些资源经过时间和社区验证，能够帮助你系统构建知识体系，少走弯路。建议根据自身情况选择合适的资源组合，制定学习计划并坚持执行。记住：<strong>资源不在多，在于消化吸收</strong>。</p></blockquote><h4 id="c-1-必读书籍" tabindex="-1">C.1 必读书籍 <a class="header-anchor" href="#c-1-必读书籍" aria-label="Permalink to &quot;C.1 必读书籍&quot;">​</a></h4><p>书籍是系统学习的最佳载体。以下书籍涵盖大模型基础原理、应用开发实战和工程实践，每本都是各自领域的代表作。建议按推荐顺序阅读，辅以实践项目加深理解。</p><h6 id="c-1-1-大模型基础与原理" tabindex="-1">C.1.1 大模型基础与原理 <a class="header-anchor" href="#c-1-1-大模型基础与原理" aria-label="Permalink to &quot;C.1.1 大模型基础与原理&quot;">​</a></h6><table tabindex="0"><thead><tr><th>书名</th><th>作者</th><th>推荐指数</th><th>难度</th><th>适合人群</th></tr></thead><tbody><tr><td>《大语言模型》</td><td>赵鑫、金文蔚等</td><td>★★★</td><td>中级</td><td>想深入理解LLM原理的开发者</td></tr><tr><td>《大规模语言模型：从理论到实践》</td><td>张奇、桂韬等</td><td>★★★</td><td>中高级</td><td>研究生、研究者、工程师</td></tr><tr><td>《Hands-On Large Language Models》</td><td>Jay Alammar、Maarten Grootendorst</td><td>★★★</td><td>初级-中级</td><td>视觉学习者、喜欢图文并茂的读者</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>《Hands-On Machine Learning with Scikit-Learn, Keras, and TensorFlow》（机器学习实战）</strong></p><ul><li>作者： Aurélien Géron</li><li>评分： ★★★</li><li>难度： 初级-中级</li><li>链接： <a href="https://github.com/ageron/handson-ml" target="_blank" rel="noreferrer">https://github.com/ageron/handson-ml</a></li><li>简介： 机器学习领域的经典入门书籍，第3版新增深度学习内容。基于Scikit-Learn、Keras和TensorFlow，覆盖从基础算法到神经网络的全栈内容。</li><li>推荐理由： 讲解深入浅出，每章配有实战项目。适合作为ML/DL的入门读物，为后续学习LLM打下基础。</li><li>特色： 800+页内容涵盖传统ML和深度学习，配有大量代码示例和Jupyter Notebook。</li></ul><hr><p><strong>《Hands-On Large Language Models》</strong></p><ul><li>作者： Jay Alammar、Maarten Grootendorst</li><li>评分： ★★★</li><li>难度： 初级-中级</li><li>链接： <a href="https://github.com/practical-llms/hands-on-llms" target="_blank" rel="noreferrer">https://github.com/practical-llms/hands-on-llms</a></li><li>简介： 275+张原创插图直观解释Attention、RAG、微调等核心概念。从Embedding到Agent架构全覆盖，每章配Jupyter Notebook。</li><li>推荐理由： Jay Alammar是知名AI科普作者，其《The Illustrated Transformer》广受好评。本书延续了视觉化教学的理念，特别适合不喜欢看纯文字的开发者。</li><li>特色： 代码驱动、图文并茂，强调可解释性和调试思维。</li></ul><hr><p><strong>《大语言模型：原理与工程实践》</strong></p><ul><li>作者： 杨青</li><li>评分： ★★★</li><li>难度： 中级</li><li>链接： 各大电商平台有售</li><li>简介： 10章全面介绍LLM，包括基础技术、预训练数据构建、有监督微调、强化对齐、性能评估、提示工程和工程实践。</li><li>推荐理由： 中文原创作品，更贴近国内开发者的学习习惯。内容涵盖从理论到实战的完整链路。</li><li>特色： 手把手教读者训练7B规模的LLM，提供可运行的代码示例。</li></ul><hr><p><strong>《大规模语言模型：从理论到实践》</strong></p><ul><li>作者： 复旦大学NLP实验室</li><li>评分： ★★★</li><li>难度： 中高级</li><li>链接： <a href="https://github.com/LLMBook-zh/LLMBook" target="_blank" rel="noreferrer">https://github.com/LLMBook-zh/LLMBook</a></li><li>简介： 详细解读构建LLM的四个阶段（预训练、有监督微调、奖励建模、强化学习），配套PPT课件和代码实现。</li><li>推荐理由： 学术团队编写，内容严谨权威。适合想深入理解GPT/BERT等技术内幕的开发者。</li><li>特色： 144页代码实战，覆盖LLMBox与YuLan工具包。</li></ul><h6 id="c-1-2-应用开发实战" tabindex="-1">C.1.2 应用开发实战 <a class="header-anchor" href="#c-1-2-应用开发实战" aria-label="Permalink to &quot;C.1.2 应用开发实战&quot;">​</a></h6><table tabindex="0"><thead><tr><th>书名</th><th>作者/来源</th><th>推荐指数</th><th>难度</th><th>适合人群</th></tr></thead><tbody><tr><td>《LangChain入门指南》</td><td>李明、高容冠等</td><td>★★★</td><td>初级</td><td>LangChain框架学习者</td></tr><tr><td>《AI Engineering》</td><td>Chip Huyen</td><td>★★★</td><td>中级</td><td>想构建端到端AI产品的工程师</td></tr><tr><td>《大模型应用开发极简入门》</td><td>卡埃朗、布莱特</td><td>★★</td><td>初级</td><td>快速上手GPT-4应用开发</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>《LangChain入门指南：构建高可复用可扩展的LLM应用程序》</strong></p><ul><li>作者： 李明、高容冠等</li><li>评分： ★★★</li><li>难度： 初级</li><li>链接： 各大电商平台有售</li><li>简介： LangChain中文社区出品，拆解模型I/O、记忆管理等六大模块，通过PDF问答系统项目展示组件化思维。</li><li>推荐理由： 大模型开发的事实标准框架指南，中文社区维护，内容与最新版本同步。</li><li>特色： 强调可复用性和可扩展性，提供企业级应用开发思路。</li></ul><hr><p><strong>《AI Engineering》</strong></p><ul><li>作者： Chip Huyen（斯坦福大学AI课程讲师）</li><li>评分： ★★★</li><li>难度： 中级</li><li>链接： <a href="https://github.com/chiphuyen/ai-engineering" target="_blank" rel="noreferrer">https://github.com/chiphuyen/ai-engineering</a></li><li>简介： 系统梳理如何用基础模型构建真实世界的AI应用，涵盖整体架构设计、数据管道、模型评估、监控与迭代、部署策略。</li><li>推荐理由： Chip Huyen曾是NVIDIA高级工程师，现为斯坦福讲师。本书填补学术研究与工业实践之间的空白。</li><li>特色： 配套资源丰富，含代码、案例与行业访谈。</li></ul><hr><p><strong>《Building LLMs for Production》</strong></p><ul><li>作者： Louis-François Bouchard、Louie Peters</li><li>评分： ★★★</li><li>难度： 中级</li><li>链接： <a href="https://github.com/practicalllms/build-llms-for-production" target="_blank" rel="noreferrer">https://github.com/practicalllms/build-llms-for-production</a></li><li>简介： 聚焦生产环境，直击痛点：如何让LLM在真实业务中稳定、高效、低成本运行。</li><li>推荐理由： 不同于“玩具项目”，专注生产级系统设计。</li><li>特色： 包含Prompt工程最佳实践、模型微调vs RAG选型、异步推理与批处理优化、幻觉监控等实用内容。</li></ul><h6 id="c-1-3-机器学习系统设计" tabindex="-1">C.1.3 机器学习系统设计 <a class="header-anchor" href="#c-1-3-机器学习系统设计" aria-label="Permalink to &quot;C.1.3 机器学习系统设计&quot;">​</a></h6><table tabindex="0"><thead><tr><th>书名</th><th>作者</th><th>推荐指数</th><th>难度</th><th>适合人群</th></tr></thead><tbody><tr><td>《Machine Learning Design Patterns》</td><td>Valliappa Lakshmanan等</td><td>★★</td><td>中级</td><td>想学习ML工程设计模式的开发者</td></tr><tr><td>《Designing Machine Learning Systems》</td><td>Chip Huyen</td><td>★★★</td><td>中高级</td><td>架构师、技术负责人</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>《Designing Machine Learning Systems》</strong></p><ul><li>作者： Chip Huyen</li><li>评分： ★★★</li><li>难度： 中高级</li><li>链接： <a href="https://github.com/chiphuyen/machine-learning-systems-design" target="_blank" rel="noreferrer">https://github.com/chiphuyen/machine-learning-systems-design</a></li><li>简介： 围绕ML系统设计的核心原则展开：关注点分离、可复现性、自动化等。包含特征存储、数据版本管理、漂移检测等生产级实践。</li><li>推荐理由： 架构层面的系统设计，适合有ML基础想进阶工程化的开发者。</li><li>特色： 理论与实践结合，每章配有实际案例。</li></ul><hr><p><strong>《Design a Machine Learning System (From Scratch)》</strong></p><ul><li>作者： Benjamin Tan Wei Hao等</li><li>评分： ★★</li><li>难度： 中级</li><li>出版： Manning，2024年</li><li>简介： 使用开源工具构建生产级ML系统，包括Kubeflow、MLFlow、BentoML、Feast等工具链。</li><li>推荐理由： MLOps实践指南，手把手教你搭建完整交付管道。</li><li>特色： 端到端项目驱动，从数据管道到模型部署全覆盖。</li></ul><hr><h4 id="c-2-在线课程" tabindex="-1">C.2 在线课程 <a class="header-anchor" href="#c-2-在线课程" aria-label="Permalink to &quot;C.2 在线课程&quot;">​</a></h4><p>系统化的课程能帮助快速建立知识框架。以下课程由顶级机构和专家讲授，涵盖从基础到实战的完整路径。</p><h6 id="c-2-1-deeplearning-ai系列" tabindex="-1">C.2.1 DeepLearning.AI系列 <a class="header-anchor" href="#c-2-1-deeplearning-ai系列" aria-label="Permalink to &quot;C.2.1 DeepLearning.AI系列&quot;">​</a></h6><p>DeepLearning.AI由深度学习先驱吴恩达创办，是AI教育领域的标杆平台。所有课程免费学习，配有交互式Notebook。</p><p><strong>课程清单：</strong></p><table tabindex="0"><thead><tr><th>课程名称</th><th>时长</th><th>难度</th><th>推荐指数</th></tr></thead><tbody><tr><td>ChatGPT Prompt Engineering for Developers</td><td>1小时</td><td>初级</td><td>★★★</td></tr><tr><td>Building Systems with the ChatGPT API</td><td>1小时</td><td>初级</td><td>★★★</td></tr><tr><td>LangChain for LLM Application Development</td><td>1小时</td><td>初级-中级</td><td>★★★</td></tr><tr><td>How Diffusion Models Work</td><td>1小时</td><td>中级</td><td>★★</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>《ChatGPT Prompt Engineering for Developers》</strong></p><ul><li>评分： ★★★</li><li>难度： 初级</li><li>链接： <a href="https://www.deeplearning.ai/short-courses/chatgpt-prompt-engineering-for-developers/" target="_blank" rel="noreferrer">https://www.deeplearning.ai/short-courses/chatgpt-prompt-engineering-for-developers/</a></li><li>简介： 吴恩达与OpenAI联合推出，9章内容涵盖提示词最佳实践、情感分类、文本总结、邮件撰写、聊天机器人搭建等。</li><li>推荐理由： 专为开发者设计的提示工程教程，代码驱动，强调实操。</li><li>特色： 使用ChatGPT Playground和API两种方式学习，配有可交互Notebook。</li></ul><hr><p><strong>《Building Systems with the ChatGPT API》</strong></p><ul><li>评分： ★★★</li><li>难度： 初级</li><li>链接： <a href="https://www.deeplearning.ai/short-courses/building-systems-with-the-chatgpt-api/" target="_blank" rel="noreferrer">https://www.deeplearning.ai/short-courses/building-systems-with-the-chatgpt-api/</a></li><li>简介： 进阶教程，教授如何通过链式调用构建复杂工作流自动化。包括提示链构建、智能客服机器人开发、安全评估等。</li><li>推荐理由： 从单轮Prompt到多轮系统的进阶路径，必学课程。</li><li>特色： 教授如何评估用户查询安全性、思维链多步推理等实战技巧。</li></ul><hr><p><strong>《LangChain for LLM Application Development》</strong></p><ul><li>评分： ★★★</li><li>难度： 初级-中级</li><li>链接： <a href="https://www.deeplearning.ai/short-courses/langchain-for-llm-application-development/" target="_blank" rel="noreferrer">https://www.deeplearning.ai/short-courses/langchain-for-llm-application-development/</a></li><li>简介： LangChain CEO Harrison Chase与吴恩达联合讲授，涵盖模型Prompt解析器、LLM内存、链、文档问答、代理等核心模块。</li><li>推荐理由： 官方教程，学完可获得专属模型作为探索AI应用的起点。</li><li>特色： 5个实战项目，代码可立即用于生产。</li></ul><h6 id="c-2-2-hugging-face官方课程" tabindex="-1">C.2.2 Hugging Face官方课程 <a class="header-anchor" href="#c-2-2-hugging-face官方课程" aria-label="Permalink to &quot;C.2.2 Hugging Face官方课程&quot;">​</a></h6><p>Hugging Face是开源LLM生态的核心贡献者，其官方课程完全免费且无广告。</p><p><strong>课程清单：</strong></p><table tabindex="0"><thead><tr><th>课程名称</th><th>章节数</th><th>难度</th><th>推荐指数</th></tr></thead><tbody><tr><td>Hugging Face LLM Course</td><td>12章</td><td>初级-中级</td><td>★★★</td></tr><tr><td>Transformers Course</td><td>12章</td><td>初级-中级</td><td>★★★</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>《Hugging Face LLM Course》</strong></p><ul><li>评分： ★★★</li><li>难度： 初级-中级</li><li>链接： <a href="https://huggingface.co/learn/llm-course/" target="_blank" rel="noreferrer">https://huggingface.co/learn/llm-course/</a></li><li>简介： 由Transformers库核心维护者讲授，涵盖LLM基础、Transformer架构、模型微调、RAG开发等。</li><li>推荐理由： 官方权威，内容与Hugging Face生态深度集成。</li><li>特色： 每章配套Colab Notebook，支持中文翻译版本。</li></ul><p><strong>《Transformers Course》</strong></p><ul><li>评分： ★★★</li><li>难度： 初级-中级</li><li>链接： <a href="https://huggingface.co/course/chapter1/1" target="_blank" rel="noreferrer">https://huggingface.co/course/chapter1/1</a></li><li>简介： 系统学习Transformers、Datasets、Tokenizers、Accelerate四大库的官方教程。</li><li>推荐理由： NLP/LLM开发的基础课程，必学内容。</li><li>特色： 分入门、进阶、高级三个层次，可根据水平选择。</li></ul><h6 id="c-2-3-国内精品课程" tabindex="-1">C.2.3 国内精品课程 <a class="header-anchor" href="#c-2-3-国内精品课程" aria-label="Permalink to &quot;C.2.3 国内精品课程&quot;">​</a></h6><table tabindex="0"><thead><tr><th>课程名称</th><th>来源</th><th>推荐指数</th><th>难度</th></tr></thead><tbody><tr><td>动手学大模型应用开发</td><td>DataWhale</td><td>★★★</td><td>初级-中级</td></tr><tr><td>Self LLM 开源大模型食用指南</td><td>DataWhale</td><td>★★</td><td>中级</td></tr><tr><td>OPEN 1+X AI通识课</td><td>DataWhale×浙大</td><td>★★</td><td>初级</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>《动手学大模型应用开发》</strong></p><ul><li>评分： ★★★</li><li>难度： 初级-中级</li><li>链接： <a href="https://github.com/datawhalechina/llm-universe" target="_blank" rel="noreferrer">https://github.com/datawhalechina/llm-universe</a></li><li>简介： DataWhale开源教程，基于个人知识库助手项目，涵盖大模型简介、API调用、知识库搭建、RAG应用构建、验证迭代。</li><li>推荐理由： 面向中文开发者，无算法基础要求，专注应用开发技能。</li><li>特色： 提供阿里云免费服务器领取指南，对硬件无要求。</li></ul><hr><p><strong>《OPEN 1+X AI通识课》</strong></p><ul><li>评分： ★★</li><li>难度： 初级</li><li>链接： <a href="https://www.datawhale.cn/open-ai" target="_blank" rel="noreferrer">https://www.datawhale.cn/open-ai</a></li><li>简介： DataWhale联合浙江大学智海Mo平台推出，产学协同的AI通识培养方案。</li><li>推荐理由： 高校认可度高，适合系统性学习AI基础。</li><li>特色： 三阶段体系（打基础→会应用→能拓展），强调动手实践。</li></ul><h6 id="c-2-4-其他优质课程" tabindex="-1">C.2.4 其他优质课程 <a class="header-anchor" href="#c-2-4-其他优质课程" aria-label="Permalink to &quot;C.2.4 其他优质课程&quot;">​</a></h6><table tabindex="0"><thead><tr><th>课程名称</th><th>平台</th><th>推荐指数</th><th>难度</th></tr></thead><tbody><tr><td>CS224N: NLP with Deep Learning</td><td>Stanford</td><td>★★★</td><td>中高级</td></tr><tr><td>Full Stack LLM Engineering</td><td>Chip Huyen</td><td>★★★</td><td>中级</td></tr><tr><td>Practical Deep Learning for Coders</td><td>fast.ai</td><td>★★</td><td>初级-中级</td></tr></tbody></table><hr><h4 id="c-3-github开源项目" tabindex="-1">C.3 GitHub开源项目 <a class="header-anchor" href="#c-3-github开源项目" aria-label="Permalink to &quot;C.3 GitHub开源项目&quot;">​</a></h4><p>实践是最好的学习方式。以下项目按难度分级，每个项目标注Star数和活跃状态，便于选择适合当前水平的练手项目。</p><h6 id="c-3-1-入门级项目" tabindex="-1">C.3.1 入门级项目 <a class="header-anchor" href="#c-3-1-入门级项目" aria-label="Permalink to &quot;C.3.1 入门级项目&quot;">​</a></h6><p>适合刚开始学习LLM应用开发的初学者，这些项目通常代码量适中、有完整文档。</p><table tabindex="0"><thead><tr><th>项目名称</th><th>Star数</th><th>语言</th><th>活跃度</th><th>推荐指数</th></tr></thead><tbody><tr><td>LangChain-Chatchat</td><td>24.8k</td><td>Python</td><td>高</td><td>★★★</td></tr><tr><td>chatgpt-on-wechat</td><td>23.1k</td><td>Python</td><td>高</td><td>★★★</td></tr><tr><td>Lobe Chat</td><td>50.5k</td><td>TypeScript</td><td>高</td><td>★★★</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>LangChain-Chatchat（原Langchain-ChatGLM）</strong></p><ul><li>Star： 24.8k</li><li>链接： <a href="https://github.com/chatchat-space/Langchain-Chatchat" target="_blank" rel="noreferrer">https://github.com/chatchat-space/Langchain-Chatchat</a></li><li>简介： 基于LangChain和开源LLM（ChatGLM、LLaMA等）的本地知识库问答系统，支持离线部署。</li><li>推荐理由： 中文社区维护，适合学习RAG架构和LangChain实战。</li><li>特色： 提供API服务和Web界面，支持多种开源模型接入。</li></ul><hr><p><strong>chatgpt-on-wechat</strong></p><ul><li>Star： 23.1k</li><li>链接： <a href="https://github.com/zhayujie/chatgpt-on-wechat" target="_blank" rel="noreferrer">https://github.com/zhayujie/chatgpt-on-wechat</a></li><li>简介： 将ChatGPT/Claude/国产大模型接入微信机器人，支持多种模型和插件扩展。</li><li>推荐理由： 有趣的入门项目，代码简洁易读。</li><li>特色： 插件化设计，可扩展性强。</li></ul><hr><p><strong>Lobe Chat</strong></p><ul><li>Star： 50.5k</li><li>链接： <a href="https://github.com/lobehub/lobe-chat" target="_blank" rel="noreferrer">https://github.com/lobehub/lobe-chat</a></li><li>简介： 现代化、可扩展的LLM聊天应用框架，支持多种AI提供商（OpenAI、Claude、Azure等）。</li><li>推荐理由： 前端设计精美，适合学习现代Web应用架构。</li><li>特色： 插件系统、Agent市场、自托管部署选项。</li></ul><h6 id="c-3-2-进阶级项目" tabindex="-1">C.3.2 进阶级项目 <a class="header-anchor" href="#c-3-2-进阶级项目" aria-label="Permalink to &quot;C.3.2 进阶级项目&quot;">​</a></h6><p>适合已掌握基础，想深入学习复杂LLM应用开发的开发者。</p><table tabindex="0"><thead><tr><th>项目名称</th><th>Star数</th><th>语言</th><th>活跃度</th><th>推荐指数</th></tr></thead><tbody><tr><td>LangChain</td><td>95.5k</td><td>Python</td><td>高</td><td>★★★</td></tr><tr><td>LlamaIndex</td><td>45k</td><td>Python</td><td>高</td><td>★★★</td></tr><tr><td>flowise</td><td>25k</td><td>TypeScript</td><td>高</td><td>★★★</td></tr><tr><td>Dify</td><td>34k</td><td>TypeScript</td><td>高</td><td>★★★</td></tr><tr><td>RAGFlow</td><td>11.6k</td><td>Python</td><td>高</td><td>★★★</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>LangChain</strong></p><ul><li>Star： 95.5k</li><li>链接： <a href="https://github.com/langchain-ai/langchain" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langchain</a></li><li>简介： LLM应用开发的核心框架，提供模块化组件（Models、Prompts、Chains、Agents、Retrieval等）。</li><li>推荐理由： 行业标准框架，必须掌握。</li><li>特色： 2025年10月发布v1.0，稳定性和易用性大幅提升。</li></ul><hr><p><strong>LlamaIndex</strong></p><ul><li>Star： 45k</li><li>链接： <a href="https://github.com/run-llama/llama_index" target="_blank" rel="noreferrer">https://github.com/run-llama/llama_index</a></li><li>简介： 数据连接框架，专注文档索引和检索增强生成（RAG）。</li><li>推荐理由： 与LangChain互补，RAG开发首选。</li><li>特色： 丰富的文档加载器、智能分块策略、查询引擎。</li></ul><hr><p><strong>Dify</strong></p><ul><li>Star： 34k</li><li>链接： <a href="https://github.com/langgenius/dify" target="_blank" rel="noreferrer">https://github.com/langgenius/dify</a></li><li>简介： 开源LLM应用开发平台，提供可视化编排、Agent设计、RAG Pipeline等功能。</li><li>推荐理由： 可视化程度高，适合快速原型开发。</li><li>特色： 支持私有化部署，企业级应用友好。</li></ul><hr><p><strong>RAGFlow</strong></p><ul><li>Star： 11.6k</li><li>链接： <a href="https://github.com/infiniflow/ragflow" target="_blank" rel="noreferrer">https://github.com/infiniflow/ragflow</a></li><li>简介： 基于深度文档理解的开源RAG引擎，提供可视化工作流设计。</li><li>推荐理由： 专注RAG场景，文档处理能力强大。</li><li>特色： 支持多种文档格式（PDF、Word、PPT等），智能分块。</li></ul><h6 id="c-3-3-高级项目" tabindex="-1">C.3.3 高级项目 <a class="header-anchor" href="#c-3-3-高级项目" aria-label="Permalink to &quot;C.3.3 高级项目&quot;">​</a></h6><p>适合想深入研究LLM系统架构、进行生产级部署的开发者。</p><table tabindex="0"><thead><tr><th>项目名称</th><th>Star数</th><th>语言</th><th>活跃度</th><th>推荐指数</th></tr></thead><tbody><tr><td>ollama</td><td>105.1k</td><td>Go</td><td>高</td><td>★★★</td></tr><tr><td>vLLM</td><td>32k</td><td>Python</td><td>高</td><td>★★★</td></tr><tr><td>graphrag (Microsoft)</td><td>22k</td><td>Python</td><td>高</td><td>★★★</td></tr><tr><td>Haystack</td><td>14.6k</td><td>Python</td><td>中</td><td>★★</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>ollama</strong></p><ul><li>Star： 105.1k</li><li>链接： <a href="https://github.com/ollama/ollama" target="_blank" rel="noreferrer">https://github.com/ollama/ollama</a></li><li>简介： 本地大模型运行平台，一键部署Llama、Qwen、Mistral等开源模型。</li><li>推荐理由： 2024年GitHub Star增长最快的开源项目之一（76k增长）。</li><li>特色： 跨平台支持（macOS/Linux/Windows），Ollama API兼容OpenAI格式。</li></ul><hr><p><strong>vLLM</strong></p><ul><li>Star： 32k</li><li>链接： <a href="https://github.com/vllm-project/vllm" target="_blank" rel="noreferrer">https://github.com/vllm-project/vllm</a></li><li>简介： 高性能LLM推理引擎，采用PagedAttention技术，支持Continuous Batching。</li><li>推荐理由： 生产环境部署首选，性能领先。</li><li>特色： 支持FP8量化、多卡并行、流式输出。</li></ul><hr><p><strong>Microsoft GraphRAG</strong></p><ul><li>Star： 22k</li><li>链接： <a href="https://github.com/microsoft/graphrag" target="_blank" rel="noreferrer">https://github.com/microsoft/graphrag</a></li><li>简介： 微软开源的图增强RAG系统，通过知识图谱提升检索和全局问答能力。</li><li>推荐理由： 解决传统RAG的语义鸿沟问题，适合复杂文档分析。</li><li>特色： 自动提取实体关系，构建层次化知识图谱。</li></ul><hr><h4 id="c-4-社区与论坛" tabindex="-1">C.4 社区与论坛 <a class="header-anchor" href="#c-4-社区与论坛" aria-label="Permalink to &quot;C.4 社区与论坛&quot;">​</a></h4><p>参与社区讨论是持续学习和解决问题的有效途径。以下社区覆盖中文和英文世界，活跃度高。</p><h6 id="c-4-1-中文社区" tabindex="-1">C.4.1 中文社区 <a class="header-anchor" href="#c-4-1-中文社区" aria-label="Permalink to &quot;C.4.1 中文社区&quot;">​</a></h6><table tabindex="0"><thead><tr><th>社区名称</th><th>类型</th><th>推荐指数</th><th>特色</th></tr></thead><tbody><tr><td>掘金</td><td>技术博客社区</td><td>★★★</td><td>AI/大模型内容丰富</td></tr><tr><td>LangChain中文社区</td><td>框架社区</td><td>★★★</td><td>中文文档和教程</td></tr><tr><td>阿里云开发者社区</td><td>综合社区</td><td>★★</td><td>通义千问相关资源丰富</td></tr><tr><td>知乎AI话题</td><td>问答社区</td><td>★★</td><td>专家文章多</td></tr><tr><td>V2EX</td><td>技术论坛</td><td>★★</td><td>开发者氛围好</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>掘金</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://juejin.cn/area/%E4%BA%BA%E5%B7%A5%E6%99%BA%E8%83%BD" target="_blank" rel="noreferrer">https://juejin.cn/area/人工智能</a></li><li>简介： 字节跳动旗下技术社区，AI和大模型内容最丰富的中文平台之一。</li><li>推荐理由： 教程质量较高，有大量实战项目分享。</li><li>特色： 标签体系完善，关注后算法推荐精准。</li></ul><hr><p><strong>LangChain中文社区</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://www.langchain.cn/" target="_blank" rel="noreferrer">https://www.langchain.cn/</a></li><li>简介： LangChain中文官方社区，提供中文文档、教程和问答。</li><li>推荐理由： 中文开发者首选的LangChain资源站。</li><li>特色： 与官方文档同步更新，有问题可快速获得解答。</li></ul><h6 id="c-4-2-英文社区" tabindex="-1">C.4.2 英文社区 <a class="header-anchor" href="#c-4-2-英文社区" aria-label="Permalink to &quot;C.4.2 英文社区&quot;">​</a></h6><table tabindex="0"><thead><tr><th>社区名称</th><th>类型</th><th>推荐指数</th><th>特色</th></tr></thead><tbody><tr><td>Hugging Face Hub</td><td>模型平台+社区</td><td>★★★</td><td>全球最大ML社区</td></tr><tr><td>LangChain Discord</td><td>框架社区</td><td>★★★</td><td>活跃度高</td></tr><tr><td>GitHub Discussions</td><td>开源讨论</td><td>★★</td><td>各项目独立频道</td></tr><tr><td>Reddit r/MachineLearning</td><td>社区论坛</td><td>★★</td><td>前沿论文讨论多</td></tr><tr><td>Hacker News</td><td>新闻聚合</td><td>★★</td><td>行业动态追踪</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>Hugging Face Hub</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://huggingface.co/" target="_blank" rel="noreferrer">https://huggingface.co/</a></li><li>简介： 全球最大的ML模型和数据集托管平台，也是开发者社区。</li><li>推荐理由： 找到任何开源模型、下载量统计、模型对比。</li><li>特色： Spaces展示Demo、模型卡片、文档全面。</li></ul><hr><p><strong>LangChain Discord</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://discord.gg/langchain" target="_blank" rel="noreferrer">https://discord.gg/langchain</a></li><li>简介： LangChain官方Discord服务器，有数千名活跃开发者。</li><li>推荐理由： 遇到问题可直接在频道提问，响应快。</li><li>特色： 分多个主题频道（beginners、agents、rag等）。</li></ul><hr><h4 id="c-5-技术博客与newsletter" tabindex="-1">C.5 技术博客与Newsletter <a class="header-anchor" href="#c-5-技术博客与newsletter" aria-label="Permalink to &quot;C.5 技术博客与Newsletter&quot;">​</a></h4><p>优质博客能帮助追踪前沿技术和最佳实践。以下按国内和国外分类，各推荐5个高质量信息源。</p><h6 id="c-5-1-国内博客与newsletter" tabindex="-1">C.5.1 国内博客与Newsletter <a class="header-anchor" href="#c-5-1-国内博客与newsletter" aria-label="Permalink to &quot;C.5.1 国内博客与Newsletter&quot;">​</a></h6><table tabindex="0"><thead><tr><th>博客名称</th><th>推荐指数</th><th>更新频率</th><th>特色</th></tr></thead><tbody><tr><td>机器之心</td><td>★★★</td><td>每日</td><td>前沿技术追踪</td></tr><tr><td>AI科技大本营</td><td>★★★</td><td>每日</td><td>技术解读深度</td></tr><tr><td>量子位</td><td>★★★</td><td>每日</td><td>产业动态丰富</td></tr><tr><td>PaperWeekly</td><td>★★</td><td>每周</td><td>论文解读专业</td></tr><tr><td>夕小瑶的卖萌屋</td><td>★★</td><td>不定期</td><td>技术人文兼具</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>机器之心</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://jiqizhixin.com/" target="_blank" rel="noreferrer">https://jiqizhixin.com/</a></li><li>简介： 国内最权威的AI科技媒体，提供技术解读、前沿论文翻译、产业分析。</li><li>推荐理由： 内容严谨，适合想深入了解AI技术进展的开发者。</li><li>特色： 设有“论文推荐”专栏，每天解读重要论文。</li></ul><hr><p><strong>AI科技大本营</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://blog.csdn.net/m0_465" target="_blank" rel="noreferrer">https://blog.csdn.net/m0_465</a> Burkhardt</li><li>简介： CSDN旗下AI技术号，教程实战性强。</li><li>推荐理由： 代码驱动的教程多，适合动手学习。</li><li>特色： 与DataWhale等社区合作内容多。</li></ul><hr><p><strong>量子位</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://www.qbitai.com/" target="_blank" rel="noreferrer">https://www.qbitai.com/</a></li><li>简介： AI产业观察媒体，提供公司动态、技术评测、创业投资等综合内容。</li><li>推荐理由： 适合了解AI行业整体发展趋势。</li><li>特色： 定期发布AI公司榜单和技术评测报告。</li></ul><h6 id="c-5-2-国外博客与newsletter" tabindex="-1">C.5.2 国外博客与Newsletter <a class="header-anchor" href="#c-5-2-国外博客与newsletter" aria-label="Permalink to &quot;C.5.2 国外博客与Newsletter&quot;">​</a></h6><table tabindex="0"><thead><tr><th>博客名称</th><th>推荐指数</th><th>更新频率</th><th>特色</th></tr></thead><tbody><tr><td>The Gradient</td><td>★★★</td><td>每周</td><td>深度技术分析</td></tr><tr><td>Hugging Face Blog</td><td>★★★</td><td>不定期</td><td>官方技术解读</td></tr><tr><td>Lil&#39;Log</td><td>★★★</td><td>不定期</td><td>工程实践深度</td></tr><tr><td>The Batch (Andrew Ng)</td><td>★★★</td><td>每周</td><td>行业趋势总结</td></tr><tr><td>Yannic Kilcher</td><td>★★</td><td>每月</td><td>论文解读视频</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>The Gradient</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://thegradient.pub/" target="_blank" rel="noreferrer">https://thegradient.pub/</a></li><li>简介： 由ML研究者和从业者运营，文章深度与可读性兼顾。</li><li>推荐理由： 不追求热点，内容有深度思考。</li><li>特色： 适合有一定基础的读者。</li></ul><hr><p><strong>Hugging Face Blog</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://huggingface.co/blog" target="_blank" rel="noreferrer">https://huggingface.co/blog</a></li><li>简介： 官方技术博客，发布新功能介绍、最佳实践和技术解读。</li><li>推荐理由： 第一手官方信息，质量有保证。</li><li>特色： 文章配有代码和Demo。</li></ul><hr><p><strong>Lil&#39;Log</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://lilianweng.github.io/" target="_blank" rel="noreferrer">https://lilianweng.github.io/</a></li><li>简介： Lilian Weng的博客，OpenAI研究科学家，内容涵盖LLM、Agent、RL等。</li><li>推荐理由： 技术深度极高，每篇文章都是系统性的知识梳理。</li><li>特色： 经典文章如《LLM Powered Autonomous Agents》是必读佳作。</li></ul><hr><h4 id="c-6-官方文档速查" tabindex="-1">C.6 官方文档速查 <a class="header-anchor" href="#c-6-官方文档速查" aria-label="Permalink to &quot;C.6 官方文档速查&quot;">​</a></h4><p>官方文档是最权威的技术参考资料。以下整理主流框架和模型的文档入口，以及快速上手的链接。</p><h6 id="c-6-1-核心框架文档" tabindex="-1">C.6.1 核心框架文档 <a class="header-anchor" href="#c-6-1-核心框架文档" aria-label="Permalink to &quot;C.6.1 核心框架文档&quot;">​</a></h6><table tabindex="0"><thead><tr><th>框架/库</th><th>文档链接</th><th>推荐指数</th><th>中文版</th></tr></thead><tbody><tr><td>LangChain</td><td><a href="https://python.langchain.com/" target="_blank" rel="noreferrer">https://python.langchain.com/</a></td><td>★★★</td><td>有</td></tr><tr><td>LlamaIndex</td><td><a href="https://docs.llamaindex.ai/" target="_blank" rel="noreferrer">https://docs.llamaindex.ai/</a></td><td>★★★</td><td>有</td></tr><tr><td>LangGraph</td><td><a href="https://langchain-ai.github.io/langgraph/" target="_blank" rel="noreferrer">https://langchain-ai.github.io/langgraph/</a></td><td>★★★</td><td>有</td></tr><tr><td>Haystack</td><td><a href="https://docs.haystack.ai/" target="_blank" rel="noreferrer">https://docs.haystack.ai/</a></td><td>★★</td><td>无</td></tr><tr><td>RAGFlow</td><td><a href="https://ragflow.io/docs/" target="_blank" rel="noreferrer">https://ragflow.io/docs/</a></td><td>★★</td><td>有</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>LangChain v1.0 官方文档</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://docs.langchain.com/" target="_blank" rel="noreferrer">https://docs.langchain.com/</a></li><li>简介： 2025年10月发布v1.0，定位为“面向生产环境的Agent构建基础框架”。</li><li>核心概念： create_agent统一API、Middleware中间件系统、Content Blocks标准化内容块。</li><li>入门路径： 安装 → 快速入门 → Agent构建 → 生产部署。</li><li>特色： 提供Python和JavaScript双版本，中文翻译版由社区维护。</li></ul><hr><p><strong>LlamaIndex文档</strong></p><ul><li>推荐指数： ★★★</li><li>链接： <a href="https://docs.llamaindex.ai/" target="_blank" rel="noreferrer">https://docs.llamaindex.ai/</a></li><li>简介： 专注数据索引和检索，提供High-Level和Low-Level两套API。</li><li>核心模块： Data Connectors、Indices、Retrievers、Query Engines、Reranking。</li><li>入门路径： 5行代码入门 → 自定义组件 → 生产部署。</li></ul><h6 id="c-6-2-国际大模型api" tabindex="-1">C.6.2 国际大模型API <a class="header-anchor" href="#c-6-2-国际大模型api" aria-label="Permalink to &quot;C.6.2 国际大模型API&quot;">​</a></h6><table tabindex="0"><thead><tr><th>模型</th><th>官方文档</th><th>API参考</th><th>推荐指数</th></tr></thead><tbody><tr><td>OpenAI GPT</td><td><a href="https://platform.openai.com/docs/" target="_blank" rel="noreferrer">https://platform.openai.com/docs/</a></td><td><a href="https://api.openai.com/" target="_blank" rel="noreferrer">https://api.openai.com/</a></td><td>★★★</td></tr><tr><td>Anthropic Claude</td><td><a href="https://docs.anthropic.com/" target="_blank" rel="noreferrer">https://docs.anthropic.com/</a></td><td><a href="https://docs.anthropic.com/claude/reference" target="_blank" rel="noreferrer">https://docs.anthropic.com/claude/reference</a></td><td>★★★</td></tr><tr><td>Google Gemini</td><td><a href="https://ai.google.dev/" target="_blank" rel="noreferrer">https://ai.google.dev/</a></td><td><a href="https://ai.google.dev/api/rest" target="_blank" rel="noreferrer">https://ai.google.dev/api/rest</a></td><td>★★</td></tr><tr><td>Meta Llama</td><td><a href="https://llama.meta.com/docs/" target="_blank" rel="noreferrer">https://llama.meta.com/docs/</a></td><td>HuggingFace</td><td>★★★</td></tr><tr><td>Mistral</td><td><a href="https://docs.mistral.ai/" target="_blank" rel="noreferrer">https://docs.mistral.ai/</a></td><td>API Reference</td><td>★★</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>OpenAI API文档</strong></p><ul><li>推荐指数： ★★★</li><li>文档链接： <a href="https://platform.openai.com/docs/" target="_blank" rel="noreferrer">https://platform.openai.com/docs/</a></li><li>API参考： <a href="https://api.openai.com/reference/" target="_blank" rel="noreferrer">https://api.openai.com/reference/</a></li><li>核心端点： /v1/chat/completions（聊天）、/v1/embeddings（向量）、/v1/images（图像生成）</li><li>认证方式： Bearer Token（API Key）</li><li>特色： Structured Outputs、Function Calling、DALL-E 3、TTS等能力。</li></ul><hr><p><strong>Anthropic Claude API文档</strong></p><ul><li>推荐指数： ★★★</li><li>文档链接： <a href="https://docs.anthropic.com/" target="_blank" rel="noreferrer">https://docs.anthropic.com/</a></li><li>核心能力： Extended Thinking（扩展思考）、Prompt Caching（提示缓存）、Tool Use（工具调用）</li><li>认证方式： x-api-key Header</li><li>特色： 支持200K上下文、HIPAA合规、零数据保留选项。</li></ul><hr><p><strong>Google Gemini API文档</strong></p><ul><li>推荐指数： ★★</li><li>文档链接： <a href="https://ai.google.dev/" target="_blank" rel="noreferrer">https://ai.google.dev/</a></li><li>核心端点： <a href="https://generativelanguage.googleapis.com/" target="_blank" rel="noreferrer">https://generativelanguage.googleapis.com/</a></li><li>特色： 多模态支持（文本、图像、音频、视频）、Function Calling。</li></ul><h6 id="c-6-3-国产大模型api" tabindex="-1">C.6.3 国产大模型API <a class="header-anchor" href="#c-6-3-国产大模型api" aria-label="Permalink to &quot;C.6.3 国产大模型API&quot;">​</a></h6><table tabindex="0"><thead><tr><th>模型</th><th>官方平台</th><th>API文档</th><th>推荐指数</th></tr></thead><tbody><tr><td>通义千问（Qwen）</td><td>阿里云百炼</td><td><a href="https://help.aliyun.com/zh/dashscope/" target="_blank" rel="noreferrer">https://help.aliyun.com/zh/dashscope/</a></td><td>★★★</td></tr><tr><td>文心一言（ERNIE）</td><td>百度智能云千帆</td><td><a href="https://wenxinyiyan.apifox.cn/" target="_blank" rel="noreferrer">https://wenxinyiyan.apifox.cn/</a></td><td>★★★</td></tr><tr><td>智谱GLM</td><td>智谱AI开放平台</td><td><a href="https://docs.bigmodel.cn/" target="_blank" rel="noreferrer">https://docs.bigmodel.cn/</a></td><td>★★★</td></tr><tr><td>Kimi（Moonshot）</td><td>Moonshot AI</td><td><a href="https://platform.moonshot.cn/docs" target="_blank" rel="noreferrer">https://platform.moonshot.cn/docs</a></td><td>★★</td></tr><tr><td>混元（Hunyuan）</td><td>腾讯云</td><td><a href="https://cloud.tencent.com/product/hunyuan" target="_blank" rel="noreferrer">https://cloud.tencent.com/product/hunyuan</a></td><td>★★</td></tr><tr><td>DeepSeek</td><td>DeepSeek</td><td><a href="https://platform.deepseek.com/docs" target="_blank" rel="noreferrer">https://platform.deepseek.com/docs</a></td><td>★★★</td></tr></tbody></table><p><strong>详细推荐：</strong></p><p><strong>通义千问（Qwen）</strong></p><ul><li>推荐指数： ★★★</li><li>官方平台： <a href="https://qianwen.aliyun.com/" target="_blank" rel="noreferrer">https://qianwen.aliyun.com/</a></li><li>API文档： <a href="https://help.aliyun.com/zh/dashscope/" target="_blank" rel="noreferrer">https://help.aliyun.com/zh/dashscope/</a></li><li>SDK： pip install dashscope</li><li>调用示例： OpenAI兼容格式，base_url替换为阿里云端点</li><li>特色： 开源版本（Qwen2.5）性能优秀，阿里云生态集成方便</li></ul><hr><p><strong>文心一言（ERNIE）</strong></p><ul><li>推荐指数： ★★★</li><li>官方平台： 百度智能云千帆</li><li>API文档： <a href="https://wenxinyiyan.apifox.cn/doc-3251584" target="_blank" rel="noreferrer">https://wenxinyiyan.apifox.cn/doc-3251584</a></li><li>SDK： pip install qianfan（百度SDK）</li><li>调用方式： 先获取Access Token，再调用API</li><li>特色： 中文理解能力业界领先，ERNIE 4.0性能强劲</li></ul><hr><p><strong>智谱GLM</strong></p><ul><li>推荐指数： ★★★</li><li>官方平台： <a href="https://bigmodel.cn/" target="_blank" rel="noreferrer">https://bigmodel.cn/</a></li><li>API文档： <a href="https://docs.bigmodel.cn/" target="_blank" rel="noreferrer">https://docs.bigmodel.cn/</a></li><li>SDK： pip install zai-sdk（新）或 pip install zhipuai（旧）</li><li>调用示例： OpenAI兼容格式</li><li>特色： GLM-4系列性能出色，支持联网搜索（GLM-4-alltools）</li></ul><hr><p><strong>DeepSeek</strong></p><ul><li>推荐指数： ★★★</li><li>官方平台： <a href="https://platform.deepseek.com/" target="_blank" rel="noreferrer">https://platform.deepseek.com/</a></li><li>API文档： <a href="https://platform.deepseek.com/docs" target="_blank" rel="noreferrer">https://platform.deepseek.com/docs</a></li><li>特色： 代码生成能力强（DeepSeek-Coder），API定价亲民</li></ul><hr><h4 id="c-7-学习路径建议" tabindex="-1">C.7 学习路径建议 <a class="header-anchor" href="#c-7-学习路径建议" aria-label="Permalink to &quot;C.7 学习路径建议&quot;">​</a></h4><p>根据不同目标和背景，提供以下学习路径：</p><h6 id="路径一-零基础入门-3个月" tabindex="-1">路径一：零基础入门（3个月） <a class="header-anchor" href="#路径一-零基础入门-3个月" aria-label="Permalink to &quot;路径一：零基础入门（3个月）&quot;">​</a></h6><p><strong>第1个月：基础储备</strong></p><ul><li>学习《Hands-On Large Language Models》建立直觉</li><li>完成DeepLearning.AI的Prompt Engineering课程</li><li>实践几个简单的ChatGPT API调用项目</li></ul><p><strong>第2个月：框架学习</strong></p><ul><li>学习LangChain或LlamaIndex官方文档</li><li>完成LangChain for LLM Application Development课程</li><li>动手做一个小型的RAG问答项目</li></ul><p><strong>第3个月：实战提升</strong></p><ul><li>学习Hugging Face Transformers课程</li><li>部署一个本地模型（Ollama）</li><li>开发一个完整的产品级应用（如知识库问答）</li></ul><h6 id="路径二-有ml基础的进阶-2个月" tabindex="-1">路径二：有ML基础的进阶（2个月） <a class="header-anchor" href="#路径二-有ml基础的进阶-2个月" aria-label="Permalink to &quot;路径二：有ML基础的进阶（2个月）&quot;">​</a></h6><p><strong>第1个月：LLM专项</strong></p><ul><li>学习LangChain v1.0新特性</li><li>深入研究RAG架构（GraphRAG等高级变体）</li><li>学习Agent开发（LangGraph）</li></ul><p><strong>第2个月：生产部署</strong></p><ul><li>学习vLLM或TGI进行推理优化</li><li>了解LLMOps工具链（Dify等）</li><li>完成一个端到端的生产项目</li></ul><h6 id="路径三-快速原型验证-1个月" tabindex="-1">路径三：快速原型验证（1个月） <a class="header-anchor" href="#路径三-快速原型验证-1个月" aria-label="Permalink to &quot;路径三：快速原型验证（1个月）&quot;">​</a></h6><p><strong>第1周：选型</strong></p><ul><li>明确需求，选择合适的框架和模型</li><li>学习Dify或Flowise等低代码平台</li></ul><p><strong>第2-3周：开发</strong></p><ul><li>快速搭建Demo</li><li>使用LangChain-Chatchat等开源项目改造</li></ul><p><strong>第4周：迭代</strong></p><ul><li>根据反馈优化Prompt</li><li>评估并选择技术方案</li></ul><hr><h4 id="c-8-资源使用技巧" tabindex="-1">C.8 资源使用技巧 <a class="header-anchor" href="#c-8-资源使用技巧" aria-label="Permalink to &quot;C.8 资源使用技巧&quot;">​</a></h4><h6 id="如何高效使用官方文档" tabindex="-1">如何高效使用官方文档 <a class="header-anchor" href="#如何高效使用官方文档" aria-label="Permalink to &quot;如何高效使用官方文档&quot;">​</a></h6><ol><li><strong>先看快速入门</strong>：每个框架的Quickstart通常10分钟能跑通Demo</li><li><strong>善用搜索</strong>：官方文档都支持搜索，快速定位API用法</li><li><strong>阅读概念指南</strong>：理解核心概念比死记API更重要</li><li><strong>查看示例代码</strong>：官方Examples通常是最可靠的学习资料</li></ol><h6 id="如何参与开源社区" tabindex="-1">如何参与开源社区 <a class="header-anchor" href="#如何参与开源社区" aria-label="Permalink to &quot;如何参与开源社区&quot;">​</a></h6><ol><li><strong>先搜索再提问</strong>：大多数问题已有解答</li><li><strong>提Issue而非问问题</strong>：发现Bug时提交Issue比在群里问更有效</li><li><strong>从文档改进开始</strong>：给开源项目改文档是很好的入门贡献</li><li><strong>分享你的学习心得</strong>：写博客或笔记，教学相长</li></ol><hr><h4 id="附录资源速查表" tabindex="-1">附录资源速查表 <a class="header-anchor" href="#附录资源速查表" aria-label="Permalink to &quot;附录资源速查表&quot;">​</a></h4><table tabindex="0"><thead><tr><th>类型</th><th>首选资源</th><th>链接</th></tr></thead><tbody><tr><td>书籍</td><td>Hands-On LLMs</td><td>GitHub: practical-llms/hands-on-llms</td></tr><tr><td>课程</td><td>DeepLearning.AI</td><td>deeplearning.ai/short-courses/</td></tr><tr><td>框架</td><td>LangChain</td><td>python.langchain.com</td></tr><tr><td>模型</td><td>HuggingFace</td><td>huggingface.co</td></tr><tr><td>社区</td><td>掘金</td><td>juejin.cn/area/人工智能</td></tr><tr><td>文档</td><td>LangChain v1.0</td><td>docs.langchain.com</td></tr></tbody></table><hr><blockquote><p><strong>提示</strong>：AI领域发展迅速，建议定期关注以上资源更新。特别关注各框架的Release Notes和官方博客，通常会有重大更新和最佳实践分享。</p></blockquote>',227)])])}const u=r(i,[["render",d]]);export{c as __pageData,u as default};
